// src/components/Charts.js
import React from 'react';
import { Bar, Line } from 'react-chartjs-2';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  Title,
  Tooltip,
  Legend,
} from 'chart.js';

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  Title,
  Tooltip,
  Legend
);

const Charts = ({ type, data, options }) => {
  const defaultOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        position: 'top',
        labels: {
          color: '#1F2937',
        },
      },
      title: {
        display: false,
        color: '#1F2937',
        font: { size: 16 },
      },
    },
    scales: {
      x: {
        ticks: { color: '#1F2937' },
        grid: { display: false },
      },
      y: {
        ticks: { color: '#1F2937' },
        grid: { color: '#E5E7EB' },
      },
    },
  };

  // Merge default options with provided options
  const mergedOptions = { ...defaultOptions, ...options };

  // Render different chart types based on the type prop
  if (type === 'bar') {
    return <Bar data={data} options={mergedOptions} />;
  } else if (type === 'line') {
    return <Line data={data} options={mergedOptions} />;
  }

  // Return null if chart type is not supported
  return null;
};

export default Charts;
